```class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string result = "";
        for (int i = a; i <= 2*a; i++) {
            for (int j = b; j <= 2*b; j++) {
                result += i % 3 == 0 ? 'a' : 'b';
            }
            result += 'a';
        }
        return result;
    }
};```

